//  KernelsLUTData.swift
//  GENERATED by scripts/gen-lut-swift.py from the literal LUT goldens
//  (formerly @embedFile'd by Native/src/kernels.zig). Do not hand-edit;
//  regenerate if the .bin goldens ever change (they are goldens: they
//  should not).

import Foundation

/// Decode the base64 chunks into the LUT bytes. Traps on corruption —
/// an embedded golden that fails to decode is a build defect, not a
/// runtime condition.
func s4DecodeLut(_ chunks: [String], expectedCount: Int) -> [UInt8] {
    guard let data = Data(base64Encoded: chunks.joined()) else {
        fatalError("KernelsLUTData: corrupt embedded LUT")
    }
    precondition(data.count == expectedCount, "KernelsLUTData: LUT size mismatch")
    return [UInt8](data)
}

